module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output [15:0] result
);

    reg [15:0] dividend_ext;
    reg [7:0] divisor_ext;
    reg sign_dividend, sign_divisor;
    reg [15:0] quotient;
    reg [7:0] remainder;
    reg [3:0] i;

    always @(*) begin
        // Determine the sign of the dividend and divisor
        sign_dividend = sign & dividend[7];
        sign_divisor = sign & divisor[7];

        // Extend the dividend and divisor to 16 bits
        dividend_ext = {sign_dividend ? 8'b11111111 : 8'b00000000, dividend};
        divisor_ext = {sign_divisor ? 8'b11111111 : 8'b00000000, divisor};

        // Initialize the quotient and remainder
        quotient = 0;
        remainder = 0;

        // Perform the division
        for (i = 0; i < 8; i = i + 1) begin
            // Shift the remainder to the left by 1 bit
            remainder = {remainder[6:0], dividend_ext[15-i]};

            // Subtract the divisor from the remainder
            if (remainder >= divisor_ext) begin
                remainder = remainder - divisor_ext;
                quotient = {quotient[14:0], 1'b1};
            end else begin
                quotient = {quotient[14:0], 1'b0};
            end
        end

        // Apply the sign to the quotient and remainder
        if (sign_dividend ^ sign_divisor) begin
            // The division result is negative
            quotient = -quotient;
            remainder = -remainder;
        end
    end

    assign result = {remainder, quotient[7:0]};

endmodule
